class ResetInstruction(ConfiguredBaseModel):
    """
    Defines the information needed to create a Reset Business Event. 
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'annotations': {'rosetta_functions': {'tag': 'rosetta_functions',
                                               'value': '[{"name":"Create_Reset","description":"Defines '
                                                        'how a Reset should be '
                                                        'constructed.","inputs":[{"name":"instruction","type":"ResetInstruction","cardinality":"1..1"},{"name":"tradeState","type":"TradeState","cardinality":"1..1"}],"output":{"name":"reset","type":"TradeState","cardinality":"1..1"}}]'}},
         'comments': ['Rosetta func: Create_Reset — Defines how a Reset should be '
                      'constructed.'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_event_common',
         'in_subset': ['cdm_event_common']})

    payout: list[Union[AssetPayout, CommodityPayout, CreditDefaultPayout, FixedPricePayout, InterestRatePayout, OptionPayout, PerformancePayout, SettlementPayout]] = Field(default=..., json_schema_extra = { "linkml_meta": {'annotations': {'metadata_reference': {'tag': 'metadata_reference',
                                                'value': True}},
         'any_of': [{'range': 'AssetPayout'},
                    {'range': 'CommodityPayout'},
                    {'range': 'CreditDefaultPayout'},
                    {'range': 'FixedPricePayout'},
                    {'range': 'InterestRatePayout'},
                    {'range': 'OptionPayout'},
                    {'range': 'PerformancePayout'},
                    {'range': 'SettlementPayout'}],
         'domain_of': ['ResetInstruction',
                       'CalculateTransferInstruction',
                       'EconomicTerms']} })
    rateRecordDate: Optional[date] = Field(default=None, description="""Specifies the 'Rate Record Day' for a Fallback rate.  Fallback rate fixing processes typically set the fixing rate in arrears, i.e., the Fallback Rate corresponding to a Rate Record Date is set at the end of the interest accural period.  When this applies, Reset->resetDate occurs at the end of the interest period, and the Reset->rateRecordDate occurs near the start of the interest period.  The Reset->rateRecordDate and Reset->observations->observationIdentifier->observationDate will differ if a Fallback rate is unavailable on the Rate Record Date, and the latest previous available rate is used as the observation.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResetInstruction', 'Reset']} })
    resetDate: date = Field(default=..., description="""Specifies the date on which the reset is occuring.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResetInstruction',
                       'Reset',
                       'RateObservation',
                       'FxLinkedNotionalAmount',
                       'FloatingRateSettingDetails']} })


