class QuantityChangeInstruction(ConfiguredBaseModel):
    """
    Instructions required to create a Quantity Change Primitive Event, which can be either an increase, a decrease or a replacement. An increase adds a new trade lot to the original trade, whereas a decrease subtracts from an existing trade lot's quantity. A replacement updates the quantity of an existing trade lot to the new value.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'annotations': {'rosetta_functions': {'tag': 'rosetta_functions',
                                               'value': '[{"name":"Create_QuantityChange","description":"A '
                                                        'specification of the inputs, '
                                                        'outputs and constraints when '
                                                        'calculating the after state '
                                                        'of a Quantity Change '
                                                        'Primitive '
                                                        'Event","inputs":[{"name":"instruction","type":"QuantityChangeInstruction","cardinality":"1..1"},{"name":"tradeState","type":"TradeState","cardinality":"1..1"}],"output":{"name":"quantityChange","type":"TradeState","cardinality":"1..1"}},{"name":"Create_OnDemandRateChangePriceChangeInstruction","description":"Creates '
                                                        'a price change instruction '
                                                        'for an on-demand rate change, '
                                                        'based on a new rate provided '
                                                        'as a single number by '
                                                        'matching it to a single rate '
                                                        'price.","inputs":[{"name":"priceQuantity","type":"PriceQuantity","cardinality":"1..*"},{"name":"newRate","type":"number","cardinality":"1..1"}],"output":{"name":"quantityChangeInstruction","type":"QuantityChangeInstruction","cardinality":"1..1"}}]'}},
         'comments': ['Rosetta func: Create_QuantityChange — A specification of the '
                      'inputs, outputs and constraints when calculating the after '
                      'state of a Quantity Change Primitive Event',
                      'Rosetta func: Create_OnDemandRateChangePriceChangeInstruction — '
                      'Creates a price change instruction for an on-demand rate '
                      'change, based on a new rate provided as a single number by '
                      'matching it to a single rate price.'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_event_common',
         'in_subset': ['cdm_event_common'],
         'slot_usage': {'lotIdentifier': {'description': 'Identifier for the new lot '
                                                         '(in case of increase) or for '
                                                         'the existing lot to be '
                                                         'changed(in case of decrease '
                                                         'or replacement). This '
                                                         'optional attribute is '
                                                         'mandatory in case of a '
                                                         'decrease or replacement if '
                                                         'the initial trade state '
                                                         'contains multiple trade '
                                                         'lots.',
                                          'multivalued': True,
                                          'name': 'lotIdentifier'}}})

    change: list[PriceQuantity] = Field(default=..., description="""Quantity by which the trade is being increased, decreased or replaced, and the price at which such quantity change is agreed. The quantity change should always be specified as a positive number, with the direction (increase/decrease/replacement) being specified by the direction enumeration. A fee can also be associated to the quantity change by specifying a Price component of type CashPrice, including the corresponding settlement date and direction.""", json_schema_extra = { "linkml_meta": {'domain_of': ['QuantityChangeInstruction']} })
    direction: QuantityChangeDirectionEnum = Field(default=..., description="""Direction of the quantity change specified as either an increase, decrease or replacement.""", json_schema_extra = { "linkml_meta": {'domain_of': ['QuantityChangeInstruction', 'DirectionRating']} })
    lotIdentifier: Optional[list[Identifier]] = Field(default=None, description="""Identifier for the new lot (in case of increase) or for the existing lot to be changed(in case of decrease or replacement). This optional attribute is mandatory in case of a decrease or replacement if the initial trade state contains multiple trade lots.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExecutionInstruction', 'QuantityChangeInstruction', 'TradeLot']} })


class IndexTransitionInstruction(ConfiguredBaseModel):
    """
    Defines the information needed to create a Index Transition Business Event.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'annotations': {'rosetta_functions': {'tag': 'rosetta_functions',
                                               'value': '[{"name":"Create_IndexTransitionTermsChange","description":"Function '
                                                        'specification to create a '
                                                        'terms change that contains '
                                                        'changes to the floating rate '
                                                        'indexes and adds an '
                                                        'adjustment spread to any '
                                                        'existing '
                                                        'spread.","inputs":[{"name":"instruction","type":"IndexTransitionInstruction","cardinality":"1..1"},{"name":"tradeState","type":"TradeState","cardinality":"1..1"}],"output":{"name":"termsChange","type":"TradeState","cardinality":"1..1"}}]'}},
         'comments': ['Rosetta condition: PriceQuantity — priceQuantity -> price -> '
                      'priceType contains PriceTypeEnum -> InterestRate and '
                      'priceQuantity -> observable -> Index -> InterestRateIndex '
                      'exists and priceQuantity -> quantity is absent',
                      'Rosetta func: Create_IndexTransitionTermsChange — Function '
                      'specification to create a terms change that contains changes to '
                      'the floating rate indexes and adds an adjustment spread to any '
                      'existing spread.'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_event_common',
         'in_subset': ['cdm_event_common'],
         'slot_usage': {'effectiveDate': {'description': 'Specifies the effective date '
                                                         'of the index transition '
                                                         'event. This is first date on '
                                                         'which the floating rate '
                                                         'calculation will use the new '
                                                         'floating rate index and '
                                                         'adjusted spread in the '
                                                         'floating rate calculation.',
                                          'name': 'effectiveDate',
                                          'required': True},
                        'priceQuantity': {'description': 'Specifies both new floating '
                                                         'rate index and spread '
                                                         'adjustment for each leg to '
                                                         'be updated.  The spread '
                                                         'adjustment accounts for the '
                                                         'difference between the old '
                                                         'floating rate index relative '
                                                         'to the new one. This spread '
                                                         'amount is added to the '
                                                         'existing spread to determine '
                                                         'the new spread, which is '
                                                         'applied from the specified '
                                                         'effective date forward. In '
                                                         'the case of the IBOR '
                                                         'Fallback Rate Adjustments, '
                                                         'the adjustment spread (also '
                                                         'known as the Fallback '
                                                         'Adjustment) accounts for two '
                                                         'distinctions: i) the fact '
                                                         'that the replacement '
                                                         'Risk-Free Rate is an '
                                                         'overnight rate while IBORs '
                                                         'have term structures (e.g., '
                                                         '1, 3, 6-month LIBOR); and '
                                                         '(ii) the historical spread '
                                                         'differential between IBORs '
                                                         'and their term equivalent '
                                                         'Overnight Risk-Free Rate '
                                                         'compounded rates.',
                                          'name': 'priceQuantity'}}})

    priceQuantity: list[PriceQuantity] = Field(default=..., description="""Specifies both new floating rate index and spread adjustment for each leg to be updated.  The spread adjustment accounts for the difference between the old floating rate index relative to the new one. This spread amount is added to the existing spread to determine the new spread, which is applied from the specified effective date forward. In the case of the IBOR Fallback Rate Adjustments, the adjustment spread (also known as the Fallback Adjustment) accounts for two distinctions: i) the fact that the replacement Risk-Free Rate is an overnight rate while IBORs have term structures (e.g., 1, 3, 6-month LIBOR); and (ii) the historical spread differential between IBORs and their term equivalent Overnight Risk-Free Rate compounded rates.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExecutionInstruction',
                       'IndexTransitionInstruction',
                       'PositionBase',
                       'PayoutBase',
                       'TradeLot']} })
    effectiveDate: date = Field(default=..., description="""Specifies the effective date of the index transition event. This is first date on which the floating rate calculation will use the new floating rate index and adjusted spread in the floating rate calculation.""", json_schema_extra = { "linkml_meta": {'close_mappings': ['fpml_5_10:CodeValue.effectiveDate'],
         'domain_of': ['CodeValue',
                       'CounterpartyPositionBusinessEvent',
                       'IndexTransitionInstruction',
                       'StockSplitInstruction',
                       'ClosedState',
                       'EventInstruction',
                       'LegalAgreementBase',
                       'MinimumTransferAmountAmendment',
                       'TerminationCurrencyAmendment',
                       'PriceQuantity',
                       'FallbackRateParameters',
                       'CalculationPeriodDates',
                       'EconomicTerms',
                       'CancelableProvision']} })
    cashTransfer: Optional[Union[ScheduledTransfer, UnscheduledTransfer]] = Field(default=None, description="""Specifies the cash transfer that can optionally be tied to an index transition event.""", json_schema_extra = { "linkml_meta": {'any_of': [{'range': 'ScheduledTransfer'}, {'range': 'UnscheduledTransfer'}],
         'domain_of': ['IndexTransitionInstruction']} })


