class DeterminationRolesAndTerms(ConfiguredBaseModel):
    """
    Defines the roles and related terms which document the agreement of parties about any determination requirements ; mostly about Extraordinary Events, without being necessarily restricted to such scope, as further specified in the particular product at stake e.g. for instance when Calculation Agent is mentioned as the Price Determination Method enumarated value, etc.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'comments': ['Rosetta condition: DisputingPartyCannotHaveOriginalRole — '
                      'whoToDetermine all <> disputingParty'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_legaldocumentation_transaction_additionalterms',
         'in_subset': ['cdm_legaldocumentation_transaction_additionalterms'],
         'slot_usage': {'disputingParty': {'description': 'Where the party who is not '
                                                          'granted with the '
                                                          'determination role at least '
                                                          'has a right to dispute the '
                                                          'determination given by the '
                                                          'counterparty with such '
                                                          'role. As an example, a '
                                                          'given PartyA is the unique '
                                                          'Counterparty with the Role '
                                                          'of CalculationAgent, yet '
                                                          'Party B could be Disputing '
                                                          'Party in regard of such '
                                                          'Role.',
                                           'name': 'disputingParty'}}})

    determinationRole: DeterminationRoleEnum = Field(default=..., description="""Defines the enumerated values to specify the determination roles to the transaction. Such roles mostly address any determination that would be required when some Extraordinary Events would happen, for instance qualifying the effectiveness of such event, or when a calculation is required, etc. else any other kind of determination as need be. Yet for clarity, other kinds of determination may be covered by such roles, which are not necessarily restricted to the scope of Extarordinary Events, depending on particular product specifications e.g. for instance when Calculation Agent is mentioned as the Price Determination Method enumarated value, etc.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DeterminationRolesAndTerms']} })
    whoToDetermine: list[CounterpartyRoleEnum] = Field(default=..., description="""Designates which Counterparty to the transaction is granted with the particular role ; cardinality of this object is 2, in case parties are both having the same role e.g. jointly CalculationAgent, jointly Determining Party, etc. """, json_schema_extra = { "linkml_meta": {'domain_of': ['DeterminationRolesAndTerms']} })
    disputingParty: Optional[CounterpartyRoleEnum] = Field(default=None, description="""Where the party who is not granted with the determination role at least has a right to dispute the determination given by the counterparty with such role. As an example, a given PartyA is the unique Counterparty with the Role of CalculationAgent, yet Party B could be Disputing Party in regard of such Role.""", json_schema_extra = { "linkml_meta": {'domain_of': ['UnderlierSubstitutionProvision', 'DeterminationRolesAndTerms']} })
    fallbackLanguageBespokeTerms: Optional[Clause] = Field(default=None, description="""Where parties may optionnaly describe any extra bespoke agreements about fallback procedure attached to a particular determination role. This fallback bespoke paragraph would typically address topics such as : delay for the Disputing Party to notify a disagreement when receiving a determination from the Calculation Agent ; Independent Third Party Dealers election terms e.g. number of Dealers to be jointly elected by the counterparties ; delay for joint election of Dealers by the counterparties ; further fallback election procedure in case of disagreement between parties to jointly elect all the Dealers e.g. typically each party designates 1 Dealer, each a Party Representant, which thus result in 2 Dealers in charge of joint election of 3 other Dealers who will be the final ones to provide the response, each a Final Dealer ; delay for joint election of the Final Dealers by the Party Representants ; fees repartition e.g. typically cost and fees incurred by the election of Dealers are equally shared by the parties ; etc.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DeterminationRolesAndTerms', 'FxDisruptionEvents']} })


