    priceExpression: Optional[PriceExpressionEnum] = Field(default=None, description="""(Optionally) Specifies whether the price is expressed in absolute or percentage terms.""", json_schema_extra = { "linkml_meta": {'domain_of': ['PriceSchedule']} })
