    arithmeticOperator: Optional[ArithmeticOperationEnum] = Field(default=None, description="""(Optionally) When the price is to be understood as an operator to apply to an observable, i.e. a spread, multiplier or min/max.""", json_schema_extra = { "linkml_meta": {'domain_of': ['PriceComposite', 'PriceSchedule']} })
    premiumType: Optional[PremiumTypeEnum] = Field(default=None, description="""(Optionally) Additional attribute that can further define any premium to the price.""", json_schema_extra = { "linkml_meta": {'domain_of': ['PriceSchedule']} })
