    firstOrSecondPeriod: Optional[DividendPeriodEnum] = Field(default=None, description="""2002 ISDA Equity Derivatives Definitions: Dividend Period as either the First Period or the Second Period. | """, json_schema_extra = { "linkml_meta": {'domain_of': ['DividendReturnTerms']} })
    extraordinaryDividendsParty: Optional[AncillaryRoleEnum] = Field(default=None, description="""Specifies the party which determines if dividends are extraordinary in relation to normal levels.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DividendReturnTerms']} })
    excessDividendAmount: Optional[DividendAmountTypeEnum] = Field(default=None, description="""Determination of Gross Cash Dividend per Share.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DividendReturnTerms']} })
    dividendCurrency: Optional[DividendCurrency] = Field(default=None, description="""Specifies the currency in which the dividend will be denominated, e.g. the dividend currency, or a specified currency. This class is not specified as such in FpML, which makes use of the CurrencyAndDeterminationMethod.model to specify such terms.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DividendReturnTerms']} })
    nonCashDividendTreatment: Optional[NonCashDividendTreatmentEnum] = Field(default=None, description="""Specifies the treatment of Non-Cash Dividends.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DividendReturnTerms']} })
