    dividendPeriod: Optional[list[DividendPeriod]] = Field(default=None, description="""One to many time bounded dividend payment periods, each with a dividend payment date per period.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DividendReturnTerms']} })


