class ReturnTermsBase(ConfiguredBaseModel):
    """
    Contains all common elements in variance, volatility and correlation return Terms.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'comments': ['Rosetta condition: InitialLevelOrInitialLevelSource — if '
                      'initialLevel is absent then initialLevelSource exists and if '
                      'initialLevelSource is absent then initialLevel exists',
                      'Rosetta condition: PositiveExpectedN — expectedN > 0'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_product_asset',
         'in_subset': ['cdm_product_asset'],
         'rules': [{'description': 'At least one of initialLevel and '
                                   'initialLevelSource must be present, or both',
                    'postconditions': {'slot_conditions': {'initialLevelSource': {'name': 'initialLevelSource',
                                                                                  'required': True}}},
                    'preconditions': {'slot_conditions': {'initialLevel': {'name': 'initialLevel',
                                                                           'required': False}}}},
                   {'description': 'The number of expected trading dates must be '
                                   'positive',
                    'postconditions': {'slot_conditions': {'expectedN': {'comments': ['Rosetta: '
                                                                                      'strictly '
                                                                                      'greater '
                                                                                      'than'],
                                                                         'minimum_value': 0,
                                                                         'name': 'expectedN'}}}}]})

    valuationTerms: ValuationTerms = Field(default=..., description="""Contains all non-date valuation information.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ReturnTermsBase']} })
    annualizationFactor: Optional[int] = Field(default=None, description="""This specifies the numerator of an annualization factor. Frequently this number is equal to the number of observations of prices in a year e.g. 252.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ReturnTermsBase']} })
    dividendApplicability: Optional[DividendApplicability] = Field(default=None, description="""The parameters which define whether dividends are applicable""", json_schema_extra = { "linkml_meta": {'domain_of': ['ReturnTermsBase']} })
    equityUnderlierProvisions: Optional[EquityUnderlierProvisions] = Field(default=None, description="""Contains Equity Underlyer provisions regarding jurisdiction and fallbacks.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ReturnTermsBase']} })
    sharePriceDividendAdjustment: Optional[bool] = Field(default=None, description="""Indicates whether the price of shares is adjusted for dividends or not.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ReturnTermsBase']} })
    expectedN: int = Field(default=..., description="""Expected number of trading days.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ReturnTermsBase']} })
    initialLevel: Optional[Decimal] = Field(default=None, description="""Contract will strike off this initial level. Providing just the initialLevel without initialLevelSource, infers that this is AgreedInitialPrice - a specified Initial Index Level.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ReturnTermsBase']} })
    initialLevelSource: Optional[DeterminationMethodEnum] = Field(default=None, description="""In this context, this is AgreedInitialPrice - a specified Initial Index Level.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ReturnTermsBase']} })
    meanAdjustment: Optional[bool] = Field(default=None, description="""Specifies whether Mean Adjustment is applicable or not in the calculation of the Realized Volatility, Variance or Correlation""", json_schema_extra = { "linkml_meta": {'domain_of': ['ReturnTermsBase']} })
    performance: Optional[str] = Field(default=None, description="""Performance calculation, in accordance with Part 1 Section 12 of the 2018 ISDA CDM Equity Confirmation for Security Equity Swap, Para 75. 'Equity Performance'. Cumulative performance is used as a notional multiplier factor on both legs of an Equity Swap.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DividendReturnTerms', 'PriceReturnTerms', 'ReturnTermsBase']} })


