    performance: Optional[str] = Field(default=None, description="""Performance calculation, in accordance with Part 1 Section 12 of the 2018 ISDA CDM Equity Confirmation for Security Equity Swap, Para 75. 'Equity Performance'. Cumulative performance is used as a notional multiplier factor on both legs of an Equity Swap.""", json_schema_extra = { "linkml_meta": {'domain_of': ['DividendReturnTerms', 'PriceReturnTerms', 'ReturnTermsBase']} })


