    floatingRateMultiplierSchedule: Optional[Schedule] = Field(default=None, description="""A rate multiplier or multiplier schedule to apply to the floating rate. A multiplier schedule is expressed as explicit multipliers and dates. In the case of a schedule, the step dates may be subject to adjustment in accordance with any adjustments specified in the calculationPeriodDatesAdjustments. The multiplier can be a positive or negative decimal. This element should only be included if the multiplier is not equal to 1 (one) for the term of the stream.""", json_schema_extra = { "linkml_meta": {'domain_of': ['FloatingRate', 'StubFloatingRate']} })
    spreadSchedule: Optional[list[SpreadSchedule]] = Field(default=None, description="""The ISDA Spread or a Spread schedule expressed as explicit spreads and dates. In the case of a schedule, the step dates may be subject to adjustment in accordance with any adjustments specified in calculationPeriodDatesAdjustments. The spread is a per annum rate, expressed as a decimal. For purposes of determining a calculation period amount, if positive the spread will be added to the floating rate and if negative the spread will be subtracted from the floating rate. A positive 10 basis point (0.1%) spread would be represented as 0.001.""", json_schema_extra = { "linkml_meta": {'domain_of': ['FloatingRateBase', 'StubFloatingRate']} })
