class ResetDates(ConfiguredBaseModel):
    """
    A data defining:  the parameters used to generate the reset dates schedule and associated fixing dates. The reset dates are the dates on which the new index value (which is observed on the fixing date) is applied for each period and on which the interest rate hence begins to accrue.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'annotations': {'metadata_key': {'tag': 'metadata_key', 'value': True}},
         'comments': ['Rosetta condition: RateCutOffDaysOffset — if '
                      'rateCutOffDaysOffset exists then rateCutOffDaysOffset -> '
                      'periodMultiplier < 0',
                      'Rosetta condition: WeeklyPeriod — if resetFrequency -> period = '
                      'PeriodExtendedEnum -> W then resetFrequency -> '
                      'weeklyRollConvention exists',
                      'Rosetta condition: NonWeeklyPeriod — if resetFrequency -> '
                      'period <> PeriodExtendedEnum -> W then resetFrequency -> '
                      'weeklyRollConvention is absent'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_product_common_schedule',
         'in_subset': ['cdm_product_common_schedule'],
         'slot_usage': {'calculationPeriodDatesReference': {'name': 'calculationPeriodDatesReference',
                                                            'required': False}}})

    calculationPeriodDatesReference: Optional[CalculationPeriodDates] = Field(default=None, description="""A pointer style reference to the associated calculation period dates component defined elsewhere in the document.""", json_schema_extra = { "linkml_meta": {'annotations': {'metadata_reference': {'tag': 'metadata_reference',
                                                'value': True}},
         'domain_of': ['StubPeriod',
                       'DateRelativeToCalculationPeriodDates',
                       'ResetDates',
                       'StubCalculationPeriodAmount']} })
    resetRelativeTo: Optional[ResetRelativeToEnum] = Field(default=None, description="""Specifies whether the reset dates are determined with respect to each adjusted calculation period start date or adjusted calculation period end date. If the reset frequency is specified as daily this element must not be included.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResetDates']} })
    initialFixingDate: Optional[InitialFixingDate] = Field(default=None, description="""The initial fixing date.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResetDates', 'InitialFixingDate']} })
    fixingDates: Optional[RelativeDateOffset] = Field(default=None, description="""The fixing dates are the dates on which the index values are observed. The fixing dates are specified by reference to the reset date through business days offset and an associated set of financial business centers. Normally these offset calculation rules will be those specified in the ISDA definition for the relevant floating rate index (ISDA's Floating Rate Option). However, non-standard offset calculation rules may apply for a trade if mutually agreed by the principal parties to the transaction.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResetDates']} })
    finalFixingDate: Optional[AdjustableDate] = Field(default=None, description="""This attribute is not part of the FpML ResetDate, and has been added as part of the CDM to support the credit derivatives final fixing date.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResetDates']} })
    rateCutOffDaysOffset: Optional[Offset] = Field(default=None, description="""Specifies the number of business days before the period end date when the rate cut-off date is assumed to apply. The financial business centers associated with determining the rate cut-off date are those specified in the reset dates adjustments. The rate cut-off number of days must be a negative integer (a value of zero would imply no rate cut off applies in which case the rateCutOffDaysOffset element should not be included). The relevant rate for each reset date in the period from, and including, a rate cut-off date to, but excluding, the next applicable period end date (or, in the case of the last calculation period, the termination date) will (solely for purposes of calculating the floating amount payable on the next applicable payment date) be deemed to be the relevant rate in effect on that rate cut-off date. For example, if rate cut-off days for a daily averaging deal is -2 business days, then the refix rate applied on (period end date - 2 days) will also be applied as the reset on (period end date - 1 day), i.e. the actual number of reset dates remains the same but from the rate cut-off date until the period end date, the same refix rate is applied. Note that in the case of several calculation periods contributing to a single payment, the rate cut-off is assumed only to apply to the final calculation period contributing to that payment. The day type associated with the offset must imply a business days offset.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResetDates']} })
    resetFrequency: Optional[ResetFrequency] = Field(default=None, description="""The frequency at which the reset dates occur. In the case of a weekly reset frequency, also specifies the day of the week that the reset occurs. If the reset frequency is greater than the calculation period frequency then this implies that more than one reset is established for each calculation period and some form of rate averaging is applicable.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResetDates']} })
    resetDatesAdjustments: Optional[BusinessDayAdjustments] = Field(default=None, description="""The definition of the business day convention and financial business centers used for adjusting the reset date if it would otherwise fall on a day that is not a business day in the specified business center.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResetDates']} })


class StubCalculationPeriodAmount(ConfiguredBaseModel):
    """
    A data defining:  how the initial or final stub calculation period amounts is calculated. For example, the rate to be applied to the initial or final stub calculation period may be the linear interpolation of two different tenors for the floating rate index specified in the calculation period amount component, e.g. A two month stub period may used the linear interpolation of a one month and three month floating rate. The different rate tenors would be specified in this component. Note that a maximum of two rate tenors can be specified. If a stub period uses a single index tenor and this is the same as that specified in the calculation period amount component then the initial stub or final stub component, as the case may be, must not be included.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_product_common_schedule',
         'in_subset': ['cdm_product_common_schedule']})

