class ResetFrequency(Frequency):
    """
    A class defining the reset frequency. In the case of a weekly reset, also specifies the day of the week that the reset occurs. If the reset frequency is greater than the calculation period frequency the this implies that more or more reset dates is established for each calculation period and some form of rate averaging is applicable. The specific averaging method of calculation is specified in FloatingRateCalculation. In case the reset frequency is of value T (term), the period is defined by the swap/swapStream/calculationPerioDates/effectiveDate and the swap/swapStream/calculationPerioDates/terminationDate.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'comments': ['Rosetta condition: FpML_ird_49 — if weeklyRollConvention exists '
                      'then period = PeriodExtendedEnum -> W'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_product_common_schedule',
         'in_subset': ['cdm_product_common_schedule']})

    weeklyRollConvention: Optional[WeeklyRollConventionEnum] = Field(default=None, description="""The day of the week on which a weekly reset date occurs. This element must be included if the reset frequency is defined as weekly and not otherwise.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResetFrequency']} })
    periodMultiplier: int = Field(default=..., description="""A time period multiplier, e.g. 1, 2, or 3. If the period value is T (Term) then period multiplier must contain the value 1.""", json_schema_extra = { "linkml_meta": {'domain_of': ['Frequency', 'Period', 'Velocity']} })
    period: PeriodExtendedEnum = Field(default=..., description="""A time period, e.g. a day, week, month, year or term of the stream.""", json_schema_extra = { "linkml_meta": {'domain_of': ['Frequency',
                       'Period',
                       'PeriodBound',
                       'CalculationFrequency',
                       'Velocity',
                       'AverageTradingVolume']} })


