class QuantityMultiplier(ConfiguredBaseModel):
    """
     Class to specify a mechanism for a quantity to be set as a multiplier to another (reference) quantity, based on a price observation. At the moment this class only supports FX or Equity-linked notional and re-uses existing building blocks for those 2 cases, until such time when component can be made more generic. This captures the case of resetting cross-currency swaps and resetting equity swaps.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_product_common_settlement',
         'in_subset': ['cdm_product_common_settlement']})

    fxLinkedNotionalSchedule: Optional[FxLinkedNotionalSchedule] = Field(default=None, description="""Multiplier specified as an FX-linked schedule, e.g. for a resetting cross-currency swap..""", json_schema_extra = { "linkml_meta": {'domain_of': ['QuantityMultiplier']} })
    multiplierValue: Optional[Decimal] = Field(default=None, json_schema_extra = { "linkml_meta": {'domain_of': ['QuantityMultiplier']} })


class ResolvablePriceQuantity(ConfiguredBaseModel):
    """
    Generic class to specify the quantity for different payout legs in a contractual product, when that quantity can vary across payout legs or across time. A resolvable quantity can always be resolved into a single quantity from the quantity notation which has a corresponding asset identifier. In addition to the base case, where quantity is directly specified as a number as part of the quantity notation, the other use cases are: (i) quantity based on some pre-defined schedule (eg amortising notional), (ii) quantity based on some pre-defined events (eg resetting cross-currency notional), or quantity set as reference to another quantity (eg equity notional as no. securities x price).
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'annotations': {'metadata_key': {'tag': 'metadata_key', 'value': True}},
         'comments': ['Rosetta condition: QuantityMultiplier — if quantityMultiplier '
                      'exists then quantityReference -> reference exists'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_product_common_settlement',
         'in_subset': ['cdm_product_common_settlement'],
         'slot_usage': {'reset': {'description': 'Whether the quantity is resettable',
                                  'name': 'reset',
                                  'range': 'boolean'}}})

    resolvedQuantity: Optional[Quantity] = Field(default=None, description="""A product's quantity as a single, non-negative amount.  When specified as part of a product definition, this quantity attribute would not be set.  Instead it is specified on the quantity notation along with an asset identifier matching this payout's asset identifier.  This allows the quantity to be resolved for a payout leg, which can then be specified here for convenience during data processing.  There needs to be at least one resolvable quantity across payout legs of a product to define an anchor that other payout quantities can refer to.  This attribute is ignored when mapping existing FpML messages.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResolvablePriceQuantity']} })
    quantitySchedule: Optional[NonNegativeQuantitySchedule] = Field(default=None, description="""A payout's quantity specified as a schedule, which may also contain a single value if that quantity is constant. There can only be a single quantity schedule applicable to a payout: e.g. the notional for an interest rate leg. The quantity must be specified outside of the payout in a PriceQuantity object and only referenced inside the payout using an address.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResolvablePriceQuantity']} })
    quantityReference: Optional[ResolvablePriceQuantity] = Field(default=None, description="""Reference quantity when resolvable quantity is defined as relative to another (resolvable) quantity. A resolvable quantity needs to contain either an absolute quantity or a reference to another (resolvable) quantity. This requirement is captured by a choice rule on the class.""", json_schema_extra = { "linkml_meta": {'annotations': {'metadata_reference': {'tag': 'metadata_reference',
                                                'value': True}},
         'domain_of': ['ResolvablePriceQuantity']} })
    quantityMultiplier: Optional[QuantityMultiplier] = Field(default=None, description="""Quantity multiplier is specified on top of a reference quantity and is used as a multiplying factor when resolving the quantity. A quantity multiplier can only exist when the resolvable quantity specifies a reference quantity.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResolvablePriceQuantity']} })
    reset: Optional[bool] = Field(default=None, description="""Whether the quantity is resettable""", json_schema_extra = { "linkml_meta": {'domain_of': ['PrimitiveInstruction', 'ResolvablePriceQuantity']} })
    futureValueNotional: Optional[FutureValueAmount] = Field(default=None, description="""The future value notional is specific to BRL CDI swaps, and is specified alongside the notional amount. The value is calculated as follows: Future Value Notional = Notional Amount * (1 + Fixed Rate) ^ (Fixed Rate Day Count Fraction). The currency should always match that expressed in the notional schedule. The value date should match the adjusted termination date.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResolvablePriceQuantity']} })
    priceSchedule: Optional[list[PriceSchedule]] = Field(default=None, description="""A payout's price specified as a schedule, which may also contain a single value if that price is constant. There may be multiple prices specified for a single payout: e.g. a floating interest rate leg may specify a spread, a cap and/or floor and a multiplier. The price must be specified outside of the payout in a PriceQuantity object and only referenced inside the payout using an address.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ResolvablePriceQuantity']} })


