                      'ancillaryParty -> role contains AncillaryRoleEnum -> '
                      'ExtraordinaryDividendsParty and if ancillaryParty -> role '
                      'contains AncillaryRoleEnum -> ExtraordinaryDividendsParty then '
                      'product -> economicTerms -> payout -> PerformancePayout -> '
                      'returnTerms -> dividendReturnTerms -> '
                      'extraordinaryDividendsParty exists',
                      'Rosetta condition: '
                      'OptionPayout_PredeterminedClearingOrganizationParty — if '
                      'product -> economicTerms -> payout -> OptionPayout -> '
                      'settlementTerms -> physicalSettlementTerms -> '
                      'predeterminedClearingOrganizationParty exists then '
                      'ancillaryParty -> role contains AncillaryRoleEnum -> '
                      'PredeterminedClearingOrganizationParty',
                      'Rosetta condition: '
                      'ForwardPayout_PredeterminedClearingOrganizationParty — if '
                      'product -> economicTerms -> payout -> SettlementPayout -> '
                      'settlementTerms -> physicalSettlementTerms -> '
                      'predeterminedClearingOrganizationParty exists then '
                      'ancillaryParty -> role contains AncillaryRoleEnum -> '
                      'PredeterminedClearingOrganizationParty',
                      'Rosetta condition: PredeterminedClearingOrganizationParty — if '
                      'ancillaryParty -> role contains AncillaryRoleEnum -> '
                      'PredeterminedClearingOrganizationParty then product -> '
                      'economicTerms -> payout -> SettlementPayout -> settlementTerms '
                      '-> physicalSettlementTerms -> '
                      'predeterminedClearingOrganizationParty exists or product -> '
                      'economicTerms -> payout -> OptionPayout -> settlementTerms -> '
                      'physicalSettlementTerms -> '
                      'predeterminedClearingOrganizationParty exists',
                      'Rosetta condition: ExerciseNoticeReceiverPartyManual — if '
                      'product -> economicTerms -> payout -> OptionPayout -> '
                      'exerciseTerms -> exerciseProcedure -> manualExercise -> '
                      'exerciseNotice -> exerciseNoticeReceiver exists then '
                      'ancillaryParty -> role contains AncillaryRoleEnum -> '
                      'ExerciseNoticeReceiverPartyManual and if ancillaryParty -> role '
                      'contains AncillaryRoleEnum -> ExerciseNoticeReceiverPartyManual '
                      'then product -> economicTerms -> payout -> OptionPayout -> '
                      'exerciseTerms -> exerciseProcedure -> manualExercise -> '
                      'exerciseNotice -> exerciseNoticeReceiver exists',
                      'Rosetta condition: '
                      'ExerciseNoticeReceiverPartyOptionalEarlyTermination — if '
                      'product -> economicTerms -> terminationProvision -> '
                      'earlyTerminationProvision -> optionalEarlyTermination -> '
                      'exerciseNotice -> exerciseNoticeReceiver exists then '
                      'ancillaryParty -> role contains AncillaryRoleEnum -> '
                      'ExerciseNoticeReceiverPartyOptionalEarlyTermination and if '
                      'ancillaryParty -> role contains AncillaryRoleEnum -> '
                      'ExerciseNoticeReceiverPartyOptionalEarlyTermination then '
                      'product -> economicTerms -> terminationProvision -> '
                      'earlyTerminationProvision -> optionalEarlyTermination -> '
                      'exerciseNotice -> exerciseNoticeReceiver exists',
                      'Rosetta condition: '
                      'ExerciseNoticeReceiverPartyCancelableProvision — if product -> '
                      'economicTerms -> terminationProvision -> cancelableProvision -> '
                      'exerciseNotice -> exerciseNoticeReceiver exists then '
                      'ancillaryParty -> role contains AncillaryRoleEnum -> '
                      'ExerciseNoticeReceiverPartyCancelableProvision and if '
