    adjustment: Optional[NotionalAdjustmentEnum] = Field(default=None, description="""Specifies the conditions that govern the adjustment to the quantity of a product being traded: e.g. execution, portfolio rebalancing etc. It is typically used in the context of Equity Swaps.""", json_schema_extra = { "linkml_meta": {'domain_of': ['TermsChangeInstruction', 'TradableProduct']} })


