class ConstituentWeight(ConfiguredBaseModel):
    """
    A class describing the weight of each of the underlier constituent within the basket, either in absolute or relative terms.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'comments': ['Rosetta condition: BasketPercentage — if basketPercentage '
                      'exists then basketPercentage >= 0.0 and basketPercentage <= '
                      '1.0'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_product_template',
         'in_subset': ['cdm_product_template'],
         'rules': [{'description': 'FpML specifies basketPercentage as a '
                                   'RestrictedPercentage type, meaning that the value '
                                   'needs to be comprised between 0 and 1.',
                    'postconditions': {'slot_conditions': {'basketPercentage': {'maximum_value': 1.0,
                                                                                'minimum_value': 0.0,
                                                                                'name': 'basketPercentage'}}},
                    'preconditions': {'slot_conditions': {'basketPercentage': {'name': 'basketPercentage',
                                                                               'required': True}}}}]})

    openUnits: Optional[Decimal] = Field(default=None, description="""The number of units (index or securities) that constitute the underlier of the swap. In the case of a basket swap, this element is used to reference both the number of basket units, and the number of each asset components of the basket when these are expressed in absolute terms.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ConstituentWeight']} })
    basketPercentage: Optional[Decimal] = Field(default=None, description="""The relative weight of each respective basket constituent, expressed in percentage. A basket percentage of 5% would be represented as 0.05.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ConstituentWeight']} })


