class ExerciseTerms(ConfiguredBaseModel):
    """
    A class defining the exercise period for an option together with any rules governing the notional amount of the underlying which can be exercised on any given exercise date and any associated exercise fees.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'annotations': {'metadata_key': {'tag': 'metadata_key', 'value': True}},
         'comments': ['Rosetta condition: ExerciseDateExpirationDateChoice — required '
                      'choice exerciseDates, expirationDate',
                      'Rosetta condition: CommencementAndExpirationDate — if '
                      'commencementDate exists then expirationDate exists',
                      'Rosetta condition: AmericanExercise — if style = '
                      'OptionExerciseStyleEnum -> American then commencementDate '
                      'exists and exerciseFee is absent and partialExercise is absent '
                      'and expirationDate count = 1',
                      'Rosetta condition: EuropeanExercise — if style = '
                      'OptionExerciseStyleEnum -> European then expirationDate exists '
                      'and exerciseFeeSchedule is absent and multipleExercise is '
                      'absent and latestExerciseTime is absent and commencementDate is '
                      'absent',
                      'Rosetta condition: BermudaExercise — if style = '
                      'OptionExerciseStyleEnum -> Bermuda then exerciseDates exists '
                      'and earliestExerciseTime exists and partialExercise is absent '
                      'and exerciseFee is absent',
                      'Rosetta condition: ExpirationTimeChoice — (if expirationTime '
                      'exists then expirationTimeType = ExpirationTimeTypeEnum -> '
                      'SpecificTime and if expirationTimeType = ExpirationTimeTypeEnum '
                      '-> SpecificTime then expirationTime exists)'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_product_template',
         'in_subset': ['cdm_product_template'],
         'rules': [{'description': 'Required choice rule between exercise dates and '
                                   'expiration date. The exerciseDates field can be '
                                   'used to extract the expiration date of a bermuda '
                                   'option, while the expirationDate field refers to '
                                   'the expiration date of an american or european '
                                   'option.',
                    'postconditions': {'exactly_one_of': [{'slot_conditions': {'exerciseDates': {'name': 'exerciseDates',
                                                                                                 'required': True}}},
                                                          {'slot_conditions': {'expirationDate': {'name': 'expirationDate',
                                                                                                  'required': True}}}]}},
                   {'description': 'Condition to check that expiration date is present '
                                   'when commencement date is present.',
                    'postconditions': {'slot_conditions': {'expirationDate': {'name': 'expirationDate',
                                                                              'required': True}}},
                    'preconditions': {'slot_conditions': {'commencementDate': {'name': 'commencementDate',
                                                                               'required': True}}}},
                   {'description': 'Condition to check that only fields expected for a '
                                   'european option are present.',
                    'postconditions': {'slot_conditions': {'commencementDate': {'name': 'commencementDate',
                                                                                'required': False},
                                                           'exerciseFeeSchedule': {'name': 'exerciseFeeSchedule',
                                                                                   'required': False},
                                                           'expirationDate': {'name': 'expirationDate',
                                                                              'required': True},
                                                           'latestExerciseTime': {'name': 'latestExerciseTime',
                                                                                  'required': False},
                                                           'multipleExercise': {'name': 'multipleExercise',
                                                                                'required': False}}},
                    'preconditions': {'slot_conditions': {'style': {'equals_string': 'European',
                                                                    'name': 'style'}}}},
                   {'description': 'Condition to check that only fields expected for a '
                                   'bermuda option are present.',
                    'postconditions': {'slot_conditions': {'earliestExerciseTime': {'name': 'earliestExerciseTime',
                                                                                    'required': True},
                                                           'exerciseDates': {'name': 'exerciseDates',
                                                                             'required': True},
                                                           'exerciseFee': {'name': 'exerciseFee',
                                                                           'required': False},
                                                           'partialExercise': {'name': 'partialExercise',
                                                                               'required': False}}},
                    'preconditions': {'slot_conditions': {'style': {'equals_string': 'Bermuda',
                                                                    'name': 'style'}}}}],
         'slot_usage': {'expirationDate': {'description': 'The last day within an '
                                                          'exercise period for an '
                                                          'American style option. For '
                                                          'a European style option it '
                                                          'is the only day within the '
                                                          'exercise period.',
                                           'multivalued': True,
                                           'name': 'expirationDate'}}})

    style: Optional[OptionExerciseStyleEnum] = Field(default=None, description="""Whether the option has a single exercise (european), multiple exercise dates (bermuda), or a continuous range of exercise (american).""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    commencementDate: Optional[AdjustableOrRelativeDate] = Field(default=None, description="""The first day of the exercise period for an American style option.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    exerciseDates: Optional[AdjustableOrRelativeDates] = Field(default=None, description="""The dates that define the Bermuda option exercise dates and the expiration date. The last specified date is assumed to be the expiration date. The dates can either be specified as a series of explicit dates and associated adjustments or as a series of dates defined relative to another schedule of dates, for example, the calculation period start dates. Where a relative series of dates are defined the first and last possible exercise dates can be separately specified.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    expirationDate: Optional[list[AdjustableOrRelativeDate]] = Field(default=None, description="""The last day within an exercise period for an American style option. For a European style option it is the only day within the exercise period.""", json_schema_extra = { "linkml_meta": {'close_mappings': ['fpml_5_10:CancelableProvision.expirationDate'],
         'domain_of': ['CancelableProvision', 'ExerciseTerms']} })
    relevantUnderlyingDate: Optional[AdjustableOrRelativeDates] = Field(default=None, description="""The effective date on the underlying product if the option is exercised.  For example, for a swaption it is the swap effective date, for an option on an FX spot or forward it is the value date for settlement, and in an extendible/cancelable provision it is the swap termination date, which is the date on which the termination is effective.'""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    earliestExerciseTime: Optional[BusinessCenterTime] = Field(default=None, description="""The earliest time at which notice of exercise can be given by the buyer to the seller (or seller's agent) to, and including, the expiration date.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    latestExerciseTime: Optional[BusinessCenterTime] = Field(default=None, description="""For a Bermuda or American style option, the latest time on an exercise business day (excluding the expiration date) within the exercise period that notice can be given by the buyer to the seller or seller's agent. Notice of exercise given after this time will be deemed to have been given on the next exercise business day.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    expirationTime: Optional[BusinessCenterTime] = Field(default=None, description="""The latest time for exercise on expirationDate. It is made mandatory given that for all option styles, this field is required.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    expirationTimeType: ExpirationTimeTypeEnum = Field(default=..., description="""The time of day at which the equity option expires, for example the official closing time of the exchange.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    multipleExercise: Optional[MultipleExercise] = Field(default=None, description="""As defined in the 2000 ISDA Definitions, Section 12.4. Multiple Exercise, the buyer of the option has the right to exercise all or less than all the unexercised notional amount of the underlying swap on one or more days in the exercise period, but on any such day may not exercise less than the minimum notional amount or more that the maximum notional amount, and if an integral multiple amount is specified, the notional amount exercised must be equal to, or be an integral multiple of, the integral multiple amount.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    exerciseFeeSchedule: Optional[ExerciseFeeSchedule] = Field(default=None, description="""The fees associated with an exercise date. The fees are conditional on the exercise occurring. The fees can be specified as actual currency amounts or as percentages of the notional amount being exercised.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    exerciseProcedure: Optional[ExerciseProcedure] = Field(default=None, description="""The set of parameters defining the procedure associated with the exercise, e.g. manual exercise.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    exerciseFee: Optional[ExerciseFee] = Field(default=None, description="""A fee to be paid on exercise. This could be represented as an amount or a rate and notional reference on which to apply the rate.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })
    partialExercise: Optional[PartialExercise] = Field(default=None, description="""As defined in the 2000 ISDA Definitions, Section 12.3. Partial Exercise, the buyer of the option has the right to exercise all or less than all the notional amount of the underlying swap on the expiration date, but may not exercise less than the minimum notional amount, and if an integral multiple amount is specified, the notional amount exercised must be equal to, or be an integral multiple of, the integral multiple amount.""", json_schema_extra = { "linkml_meta": {'domain_of': ['ExerciseTerms']} })


