class PartialExercise(ConfiguredBaseModel):
    """
    A class defining partial exercise. As defined in the 2000 ISDA Definitions, Section 12.3 Partial Exercise, the buyer of the option may exercise all or less than all the notional amount of the underlying swap but may not be less than the minimum notional amount (if specified) and must be an integral multiple of the integral multiple amount if specified.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'comments': ['Rosetta condition: MinimumChoice — required choice '
                      'minimumNotionalAmount, minimumNumberOfOptions'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_product_template',
         'in_subset': ['cdm_product_template'],
         'rules': [{'description': 'Choice rule to represent an FpML choice construct.',
                    'postconditions': {'exactly_one_of': [{'slot_conditions': {'minimumNotionalAmount': {'name': 'minimumNotionalAmount',
                                                                                                         'required': True}}},
                                                          {'slot_conditions': {'minimumNumberOfOptions': {'name': 'minimumNumberOfOptions',
                                                                                                          'required': True}}}]}}],
         'slot_usage': {'notionalReference': {'description': 'A pointer style '
                                                             'reference to the '
                                                             'associated notional '
                                                             'schedule defined '
                                                             'elsewhere in the '
                                                             'document. This element '
                                                             'has been made optional '
                                                             'as part of its '
                                                             'integration in the '
                                                             'OptionBaseExtended, '
                                                             'because not required for '
                                                             'the options on '
                                                             'securities.',
                                              'name': 'notionalReference',
                                              'required': False}}})

    notionalReference: Optional[Money] = Field(default=None, description="""A pointer style reference to the associated notional schedule defined elsewhere in the document. This element has been made optional as part of its integration in the OptionBaseExtended, because not required for the options on securities.""", json_schema_extra = { "linkml_meta": {'annotations': {'metadata_reference': {'tag': 'metadata_reference',
                                                'value': True}},
         'domain_of': ['ExerciseFee', 'ExerciseFeeSchedule', 'PartialExercise']} })
    integralMultipleAmount: Optional[Decimal] = Field(default=None, description="""A notional amount which restricts the amount of notional that can be exercised when partial exercise or multiple exercise is applicable. The integral multiple amount defines a lower limit of notional that can be exercised and also defines a unit multiple of notional that can be exercised, i.e. only integer multiples of this amount can be exercised.""", json_schema_extra = { "linkml_meta": {'domain_of': ['PartialExercise']} })
    minimumNotionalAmount: Optional[Decimal] = Field(default=None, description="""The minimum notional amount that can be exercised on a given exercise date. See multipleExercise.""", json_schema_extra = { "linkml_meta": {'domain_of': ['PartialExercise']} })
    minimumNumberOfOptions: Optional[int] = Field(default=None, description="""The minimum number of options that can be exercised on a given exercise date.""", json_schema_extra = { "linkml_meta": {'domain_of': ['PartialExercise']} })


class MultipleExercise(PartialExercise):
    """
    A class defining multiple exercises. As defined in the 2000 ISDA Definitions, Section 12.4. Multiple Exercise, the buyer of the option has the right to exercise all or less than all the unexercised notional amount of the underlying swap on one or more days in the exercise period, but on any such day may not exercise less than the minimum notional amount or more than the maximum notional amount, and if an integral multiple amount is specified, the notional exercised must be equal to or, be an integral multiple of, the integral multiple amount. In FpML, MultipleExercise is built upon the PartialExercise.model.
    """
    linkml_meta: ClassVar[LinkMLMeta] = LinkMLMeta({'comments': ['Rosetta condition: MaximumChoice — required choice '
                      'maximumNotionalAmount, maximumNumberOfOptions',
                      'Rosetta condition: MaximumNumberOfOptions — if '
                      'maximumNumberOfOptions exists then maximumNotionalAmount >= 0',
                      'Rosetta condition: MinimumNumberOfOptions — if '
                      'minimumNumberOfOptions exists then minimumNumberOfOptions >= 0'],
         'from_schema': 'https://w3id.org/lmodel/common-domain-model/cdm_product_template',
         'in_subset': ['cdm_product_template'],
         'rules': [{'description': 'Choice rule to represent an FpML choice construct.',
                    'postconditions': {'exactly_one_of': [{'slot_conditions': {'maximumNotionalAmount': {'name': 'maximumNotionalAmount',
                                                                                                         'required': True}}},
                                                          {'slot_conditions': {'maximumNumberOfOptions': {'name': 'maximumNumberOfOptions',
                                                                                                          'required': True}}}]}},
                   {'description': 'FpML MultipleExercise construct specifies the '
                                   'maximumNumberOfOptions as a positive integer.',
                    'postconditions': {'slot_conditions': {'maximumNotionalAmount': {'minimum_value': 0,
                                                                                     'name': 'maximumNotionalAmount'}}},
                    'preconditions': {'slot_conditions': {'maximumNumberOfOptions': {'name': 'maximumNumberOfOptions',
                                                                                     'required': True}}}},
                   {'description': 'FpML MultipleExercise construct specifies the '
                                   'minimumNumberOfOptions as a positive integer.',
                    'postconditions': {'slot_conditions': {'minimumNumberOfOptions': {'minimum_value': 0,
                                                                                      'name': 'minimumNumberOfOptions'}}},
                    'preconditions': {'slot_conditions': {'minimumNumberOfOptions': {'name': 'minimumNumberOfOptions',
                                                                                     'required': True}}}}]})

    maximumNotionalAmount: Optional[Decimal] = Field(default=None, description="""The maximum notional amount that can be exercised on a given exercise date.""", json_schema_extra = { "linkml_meta": {'domain_of': ['MultipleExercise']} })
    maximumNumberOfOptions: Optional[int] = Field(default=None, description="""The maximum number of options that can be exercised on a given exercise date. If the number is not specified, it means that the maximum number of options corresponds to the remaining unexercised options.""", json_schema_extra = { "linkml_meta": {'domain_of': ['MultipleExercise']} })
    notionalReference: Optional[Money] = Field(default=None, description="""A pointer style reference to the associated notional schedule defined elsewhere in the document. This element has been made optional as part of its integration in the OptionBaseExtended, because not required for the options on securities.""", json_schema_extra = { "linkml_meta": {'annotations': {'metadata_reference': {'tag': 'metadata_reference',
                                                'value': True}},
         'domain_of': ['ExerciseFee', 'ExerciseFeeSchedule', 'PartialExercise']} })
    integralMultipleAmount: Optional[Decimal] = Field(default=None, description="""A notional amount which restricts the amount of notional that can be exercised when partial exercise or multiple exercise is applicable. The integral multiple amount defines a lower limit of notional that can be exercised and also defines a unit multiple of notional that can be exercised, i.e. only integer multiples of this amount can be exercised.""", json_schema_extra = { "linkml_meta": {'domain_of': ['PartialExercise']} })
    minimumNotionalAmount: Optional[Decimal] = Field(default=None, description="""The minimum notional amount that can be exercised on a given exercise date. See multipleExercise.""", json_schema_extra = { "linkml_meta": {'domain_of': ['PartialExercise']} })
    minimumNumberOfOptions: Optional[int] = Field(default=None, description="""The minimum number of options that can be exercised on a given exercise date.""", json_schema_extra = { "linkml_meta": {'domain_of': ['PartialExercise']} })


